// Plugin Frontend Scanner
// Build-time tool that scans plugins/*/frontend/ directories
// and generates proxy Astro pages + runtime registry.
//
// Run before `astro build` / `astro dev`.
// Generated files are gitignored.

import fs from 'node:fs';
import path from 'node:path';
import {fileURLToPath} from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const PROJECT_ROOT = path.resolve(__dirname, '..');
const FRONTEND_DIR = path.join(PROJECT_ROOT, 'frontend-astro');
const PLUGINS_DIR = path.join(PROJECT_ROOT, 'plugins');
const GENERATED_SRC = path.join(FRONTEND_DIR, 'src', '.plugin-pages');
const REGISTRY_FILE = path.join(FRONTEND_DIR, 'src', '.plugin-registry.ts');
const PROXY_PAGES_DIR = path.join(FRONTEND_DIR, 'src', 'pages', 'admin', 'plugin-pages');

function log(msg) {
  console.log(`[plugin-scanner] ${msg}`);
}

function scanPlugins() {
  if (!fs.existsSync(PLUGINS_DIR)) {
    log('No plugins/ directory found.');
    return [];
  }

  const entries = fs.readdirSync(PLUGINS_DIR, { withFileTypes: true });
  const plugins = [];

  for (const entry of entries) {
    if (!entry.isDirectory()) continue;
    const manifestPath = path.join(PLUGINS_DIR, entry.name, 'frontend', 'manifest.json');
    if (!fs.existsSync(manifestPath)) continue;

    try {
      const manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf-8'));
      plugins.push({ slug: entry.name, manifest });
      log(`Found plugin frontend: ${entry.name}`);
    } catch (e) {
      log(`Warning: Failed to parse manifest for ${entry.name}: ${e.message}`);
    }
  }

  return plugins;
}

function copyPluginSource(slug) {
  const srcDir = path.join(PLUGINS_DIR, slug, 'frontend');
  const destDir = path.join(GENERATED_SRC, slug);

  // Clean and recreate
  fs.rmSync(destDir, { recursive: true, force: true });

  // Copy all files recursively (excluding node_modules, if any)
  function copyRecursive(src, dest) {
    fs.mkdirSync(dest, { recursive: true });
    const items = fs.readdirSync(src, { withFileTypes: true });
    for (const item of items) {
      const srcPath = path.join(src, item.name);
      const destPath = path.join(dest, item.name);
      if (item.isDirectory()) {
        if (item.name !== 'node_modules') copyRecursive(srcPath, destPath);
      } else {
        fs.copyFileSync(srcPath, destPath);
      }
    }
  }

  if (fs.existsSync(srcDir)) {
    copyRecursive(srcDir, destDir);
    log(`Copied frontend source: ${slug} → .plugin-pages/${slug}/`);
  }
}

function generateRegistry(plugins) {
  const navItems = [];
  const routeImports = [];

  for (const { slug, manifest } of plugins) {
    const routes = manifest.routes || [];
    const nav = manifest.navItems || [];

    for (const item of nav) {
      navItems.push({ label: item.label, href: item.href, icon: item.icon || 'Puzzle' });
    }

    for (const route of routes) {
      // Strip leading slash and map to import path
      const cleanPath = route.path.replace(/^\//, '');
      routeImports.push({ path: cleanPath, slug, component: route.component });
    }
  }

  let code = `// Auto-generated by plugin-frontend-scanner — do not edit
// Regenererated on every build.

export interface PluginNavItem {
  label: string;
  href: string;
  icon: string;
}

export interface PluginRoute {
  path: string;
  slug: string;
}

export const pluginNavItems: PluginNavItem[] = ${JSON.stringify(navItems, null, 2)};

export const pluginRoutes: PluginRoute[] = ${JSON.stringify(routeImports.map(r => ({ path: r.path, slug: r.slug })), null, 2)};
`;

  fs.writeFileSync(REGISTRY_FILE, code, 'utf-8');
  log(`Generated .plugin-registry.ts (${navItems.length} nav items, ${routeImports.length} routes)`);
}

function generateProxyPages(plugins) {
  // Clean old proxy pages
  fs.rmSync(PROXY_PAGES_DIR, { recursive: true, force: true });

  for (const { slug, manifest } of plugins) {
    const routes = manifest.routes || [];

    for (const route of routes) {
      // Determine the URL path relative to admin/_plugins/
      // e.g. route.path = "/admin/snippets" → path parts = ["admin", "snippets"]
      // We strip the leading / and map to a filesystem path
      const cleanPath = route.path.replace(/^\//, '');
      const parts = cleanPath.split('/');

      // Always under admin/_plugins/ namespace
      // route.path "/admin/snippets" → pages/admin/_plugins/snippets/index.astro
      // The "admin" in the route path gets absorbed into our proxy location
      // Actually: route.path "/admin/snippets" - the user wants the URL to be /admin/snippets
      // But we need to serve it from /admin/_plugins/snippets to avoid conflicts
      // So we map: route.path → admin/_plugins/<slug>/index.astro if it's a simple page

      // Simpler approach: all plugin routes go to /admin/_plugins/<slug>/
      const pageDir = path.join(PROXY_PAGES_DIR, slug);
      const pageFile = path.join(pageDir, 'index.astro');

      fs.mkdirSync(pageDir, { recursive: true });

      // Determine component import path — strip leading "./" if present
      const cleanComponent = route.component.replace(/^\.\//, '');
      const componentImport = `@/.plugin-pages/${slug}/${cleanComponent}`;

      const astroContent = `---
// Auto-generated proxy page for plugin "${slug}"
export const prerender = false;
import PluginPage from '${componentImport}';
---
<html lang="zh-CN">
<head>
  <title>${route.title || manifest.name || slug} - FastBlog</title>
  <link rel="stylesheet" href="/src/styles/globals.css"/>
</head>
<body>
  <PluginPage client:idle />
</body>
</html>
`;
      fs.writeFileSync(pageFile, astroContent, 'utf-8');
      log(`Generated proxy page: /admin/plugin-pages/${slug}/ (→ ${route.component})`);
    }
  }
}

// ─── Main ────────────────────────────────────────
export function scanPluginFrontend() {
  log('Scanning for plugin frontend sources...');
  const plugins = scanPlugins();
  if (plugins.length === 0) {
    log('No plugin frontends found. Cleaning up generated files.');
    fs.rmSync(GENERATED_SRC, { recursive: true, force: true });
    fs.rmSync(PROXY_PAGES_DIR, { recursive: true, force: true });
    generateRegistry([]);
    return;
  }

  for (const { slug } of plugins) {
    copyPluginSource(slug);
  }
  generateRegistry(plugins);
  generateProxyPages(plugins);
  log(`Done. Processed ${plugins.length} plugin(s).`);
}

// Run directly (Windows-safe check)
const isMain = process.argv[1] && (
  process.argv[1].replace(/\\/g, '/').endsWith('scan-plugin-frontend.mjs')
);
if (isMain) {
  scanPluginFrontend();
}
